import { useRef, useState } from "react";

function RatingAverage() {
  const inputRef = useRef(null);
  const previousValueRef = useRef(null);
  const [average, setAverage] = useState("—");

  const handleSubmit = () => {
    const currentValue = Number(inputRef.current.value);

    if (Number.isNaN(currentValue)) {
      return;
    }

    if (previousValueRef.current === null) {
      setAverage(currentValue);
    } else {
      setAverage((previousValueRef.current + currentValue) / 2);
    }

    previousValueRef.current = currentValue;
    inputRef.current.value = "";
  };

  return (
    <section className="rating-average">
      <div className="rating-average__controls">
        <label htmlFor="rating-input">Введите число:</label>
        <input
          ref={inputRef}
          id="rating-input"
          type="number"
          step="any"
          defaultValue="5"
        />
        <button type="button" onClick={handleSubmit}>
          Отправить
        </button>
      </div>

      <p className="rating-average__result">Среднее значение: {average}</p>
    </section>
  );
}

export default RatingAverage;
